import { streamText } from 'ai';
import { z } from 'zod';

const detectHallucination = (chunks: string[]) => {
  const tokens = chunks.flatMap(chunk => chunk.split(' '));
  const confidenceDrops = [];

  for (let i = 1; i < tokens.length - 1; i++) {
    const prev = tokens[i-1].toLowerCase();
    const curr = tokens[i].toLowerCase();
    const next = tokens[i+1].toLowerCase();

    // Detect contradiction patterns
    if ((prev.includes('berlin') && next.includes('paris')) ||
        (prev.includes('false') && next.includes('true'))) {
      confidenceDrops.push({
        position: i,
        pattern: `${prev} → ${curr} → ${next}`,
        score: 0.9
      });
    }
  }

  return confidenceDrops.length > 0;
};

// Usage in streamText
const result = await streamText({
  model: openai('gpt-4o'),
  chunks: chunks => {
    if (detectHallucination(chunks)) {
      throw new Error('Hallucination detected in stream');
    }
  }
});

import { tool } from 'ai/rsc';
import { z } from 'zod';

const validateToolResult = (toolName: string, result: any): boolean => {
  const schemas = {
    weather: z.object({
      temperature: z.number(),
      condition: z.enum(['sunny', 'rainy', 'cloudy']),
      location: z.string().min(1)
    }),
    calculator: z.object({
      result: z.number(),
      expression: z.string()
    })
  };

  const schema = schemas[toolName as keyof typeof schemas];
  if (!schema) return true;

  return schema.safeParse(result).success;
};

const weatherTool = tool({
  description: 'Get weather',
  parameters: z.object({ location: z.string() }),
  execute: async ({ location }) => {
    const result = await fetchWeather(location);

    if (!validateToolResult('weather', result)) {
      console.error('Invalid tool result:', result);
      return { error: 'Invalid weather data', valid: false };
    }

    return result;
  }
});

import { generateText } from 'ai';
import OpenAI from 'openai';
import Anthropic from '@anthropic-ai/sdk';

const testStructuredOutput = async () => {
  const prompt = 'Extract JSON: { "capital": "Paris", "country": "France" }';
  const providers = ['openai', 'anthropic', 'google'];
  const results = [];

  for (const provider of providers) {
    let result;

    if (provider === 'openai') {
      result = await generateText({
        model: new OpenAI().chat.completions.create.bind(new OpenAI()),
        prompt,
        response_format: { type: 'json_object' }
      });
    } else if (provider === 'anthropic') {
      result = await generateText({
        model: new Anthropic().messages.create.bind(new Anthropic()),
        prompt,
        max_tokens: 500
      });
    }

    const isValidJson = (str: string) => {
      try {
        JSON.parse(str);
        return true;
      } catch {
        return false;
      }
    };

    results.push({
      provider,
      valid: isValidJson(result.text),
      length: result.text.length
    });
  }

  const failureRate = results.filter(r => !r.valid).length / results.length;
  console.log(`JSON consistency failure rate: ${failureRate.toFixed(2)}`);
  return failureRate > 0.3;
};

