import { streamText, StreamingTextResponse } from 'ai';

const createValidatedStream = (model: any) => {
  return async (messages: any[]) => {
    let buffer = '';
    const validations = [];

    const stream = await streamText({
      model,
      messages,
      onChunk: (chunk) => {
        buffer += chunk;

        // Validate every 5 tokens
        if (buffer.split(' ').length % 5 === 0) {
          validations.push(validateBuffer(buffer));
        }
      }
    });

    return new StreamingTextResponse(stream, {
      headers: {
        'x-validation-passed': validations.every(v => v.valid).toString()
      }
    });
  };
};

const validateBuffer = (text: string) => {
  // Check for common hallucination reversal patterns
  const badPatterns = [
    /berlin.*?(?=paris|france)/i,
    /false.*?true/i,
    /no.*?yes/i
  ];

  return {
    valid: !badPatterns.some(p => p.test(text)),
    score: 1 - (badPatterns.filter(p => p.test(text)).length / badPatterns.length)
  };
};

import { tool } from 'ai/rsc';
import { z } from 'zod';

const safeTool = <T extends z.ZodSchema>(baseTool: any, schema: T) => {
  return {
    ...baseTool,
    execute: async (...args: any[]) => {
      try {
        const result = await baseTool.execute(...args);
        const parsed = schema.safeParse(result);

        if (!parsed.success) {
          console.error('Tool validation failed:', parsed.error);
          return {
            __validationError: true,
            error: 'Invalid tool response format',
            fallback: 'Tool failed to return valid data'
          };
        }

        return parsed.data;
      } catch (error) {
        return {
          __validationError: true,
          error: error.message,
          fallback: 'Tool execution failed'
        };
      }
    }
  };
};

