import { generateText } from 'ai';
import { z } from 'zod';

const extractStructured = async <T extends z.ZodSchema>(
  model: any,
  prompt: string,
  schema: T
): Promise<z.infer<T> | null> => {
  const result = await generateText({
    model,
    prompt: `Respond with valid JSON matching this schema only:\n${schema.safeParse({}).error?.message}\n\n${prompt}`,
    temperature: 0.1,
    maxTokens: 2000
  });

  // Multi-strategy JSON extraction
  const extractors = [
    () => {
      const jsonMatch = result.text.match(/\{[`\s\S]*?\}/);
      return jsonMatch ? jsonMatch[0] : null;
    },
    () => {
      const start = result.text.indexOf('{');
      const end = result.text.lastIndexOf('}');
      return start !== -1 && end !== -1 ? result.text.slice(start, end + 1) : null;
    }
  ];

  for (const extractor of extractors) {
    try {
      const jsonStr = extractor();
      if (jsonStr) {
        const parsed = schema.safeParse(JSON.parse(jsonStr));
        if (parsed.success) return parsed.data;
      }
    } catch (e) {
      continue;
    }
  }

  return null;
};

